/* lowlevel_file.c */
#include "lowlevel_file.h"
#include <string.h> // for memcpy and memset
#include <unistd.h>
#include "lowlevel_file.h"
#include <string.h>
#include <stdio.h>

#define INLINE_DATA_SIZE (PG_SIZE - 64)

#include "common.h"

extern struct counter cnt;

void file_allocate(struct inode *inode, unsigned offset, unsigned len) {
    if (len == 0) return;

    unsigned start = offset;
    unsigned end = offset + len - 1;
    unsigned inline_end = INLINE_DATA_SIZE - 1;

    // Handle regular pages allocation for ranges beyond inline data
    if (end <= inline_end) return;

    unsigned page_start = (start > inline_end) ? start : (inline_end + 1);
    unsigned page_len = end - page_start + 1;

    // Calculate adjusted offset for indextb (0-based for post-inline data)
    unsigned adjusted_offset = page_start - INLINE_DATA_SIZE;
    unsigned adjusted_len = page_len;

    struct indextb *tb = inode->file;
    unsigned start_page = adjusted_offset / PG_SIZE;
    unsigned end_byte = adjusted_offset + adjusted_len - 1;
    unsigned end_page = end_byte / PG_SIZE;

    for (unsigned page = start_page; page <= end_page; page++) {
        if (page >= INDEXTB_NUM) break;
        if (tb->index[page] == NULL) {
            tb->index[page] = malloc_page();
        }
    }
}

void file_read(struct inode *inode, unsigned offset, unsigned len, char *data) {
    unsigned remaining = len;
    unsigned current_offset = offset;
    char *dest = data;
    unsigned inline_size = INLINE_DATA_SIZE;

    // Read from inline_data
    if (current_offset < inline_size) {
        unsigned copy_bytes = inline_size - current_offset;
        if (copy_bytes > remaining) copy_bytes = remaining;
        
        memcpy(dest, inode->inline_data + current_offset, copy_bytes);
        dest += copy_bytes;
        current_offset += copy_bytes;
        remaining -= copy_bytes;
    }

    // Read from regular pages
    if (remaining > 0) {
        unsigned adjusted_offset = current_offset - inline_size;
        struct indextb *tb = inode->file;

        while (remaining > 0) {
            unsigned page = adjusted_offset / PG_SIZE;
            unsigned page_offset = adjusted_offset % PG_SIZE;
            unsigned copy_bytes = PG_SIZE - page_offset;
            if (copy_bytes > remaining) copy_bytes = remaining;

            unsigned char *page_data = (page < INDEXTB_NUM) ? tb->index[page] : NULL;
            
            if (page_data) {
                memcpy(dest, page_data + page_offset, copy_bytes);
            } else {
                memset(dest, 0, copy_bytes);
            }

            dest += copy_bytes;
            adjusted_offset += copy_bytes;
            remaining -= copy_bytes;
        }
    }

    //  after allocation, iterate through all files and count its file block nums and sum them up
    unsigned total_blocks = 0;
    for (unsigned i = 0; i < cnt.size; i++) {
        struct inode *file_inode = cnt.files[i];
        if (file_inode->file != NULL) {
            for (unsigned j = 0; j < INDEXTB_NUM; j++) {
                if (file_inode->file->index[j] != NULL) {
                    total_blocks++;
                }
            }
        }
    }
    
    FILE *fp = fopen("data_block_count", "w");
    if (fp) {
        fprintf(fp, "%u", total_blocks);
        fclose(fp);
    }
    //  end of counting
}

void file_write(struct inode *inode, unsigned offset, unsigned len, const char *data) {
    unsigned remaining = len;
    unsigned current_offset = offset;
    const char *src = data;
    unsigned inline_size = INLINE_DATA_SIZE;

    // Write to inline_data
    if (current_offset < inline_size) {
        unsigned copy_bytes = inline_size - current_offset;
        if (copy_bytes > remaining) copy_bytes = remaining;

        if (src) {
            memcpy(inode->inline_data + current_offset, src, copy_bytes);
            src += copy_bytes;
        } else {
            memset(inode->inline_data + current_offset, 0, copy_bytes);
        }

        current_offset += copy_bytes;
        remaining -= copy_bytes;
    }

    // Write to regular pages
    if (remaining > 0) {
        file_allocate(inode, current_offset, remaining);
        unsigned adjusted_offset = current_offset - inline_size;
        struct indextb *tb = inode->file;

        while (remaining > 0) {
            unsigned page = adjusted_offset / PG_SIZE;
            unsigned page_offset = adjusted_offset % PG_SIZE;
            unsigned copy_bytes = PG_SIZE - page_offset;
            if (copy_bytes > remaining) copy_bytes = remaining;

            if (page >= INDEXTB_NUM || tb->index[page] == NULL) {
                if (src) src += copy_bytes;
                adjusted_offset += copy_bytes;
                remaining -= copy_bytes;
                continue;
            }

            unsigned char *page_data = tb->index[page];

            if (src) {
                memcpy(page_data + page_offset, src, copy_bytes);
                src += copy_bytes;
            } else {
                memset(page_data + page_offset, 0, copy_bytes);
            }

            adjusted_offset += copy_bytes;
            remaining -= copy_bytes;
        }
    }
}

void clear_file(struct inode *node, unsigned start, unsigned len) {
    file_write(node, start, len, NULL);
}